INSERT OR REPLACE INTO books (slug,number,title,subtitle,setting_place,setting_region,era,age_range,page_count,word_count,updated_at) VALUES ('01-the-shed-the-cube-and-the-sands-of-time',1,'The Shed, The Cube, and The Sands of Time','A Time-Travel Adventure in Ancient Egypt','Ancient Egypt, the Nile Valley near the construction of the Great Pyramid of Giza; framed by the Carver family''s home on Oakdale Road in 1986','Egypt','Old Kingdom Egypt, reign of Pharaoh Khufu, c. 2560 BCE, with a contemporary frame story set in 1986','8–12 (middle grade)',591,127754,'2026-07-14T00:00:00.000Z');
