INSERT OR REPLACE INTO books (slug,number,title,subtitle,setting_place,setting_region,era,age_range,page_count,word_count,updated_at) VALUES ('08-the-seed-the-soil-and-the-cities-beneath-the-green',8,'The Seed, The Soil, and The Cities Beneath the Green','A Time-Travel Adventure in the Ancient Amazon','An Amazonian food-forest civilization of raised causeways, ring-villages, fish weirs, and manufactured black-earth (terra preta) soil','Ancient Amazon rainforest, South America','A precolumbian Amazonian society built up over roughly four thousand years of continuous forest-tending','8-12',174,48997,'2026-07-14T00:00:00.000Z');
