INSERT OR REPLACE INTO books (slug,number,title,subtitle,setting_place,setting_region,era,age_range,page_count,word_count,updated_at) VALUES ('10-the-fire-the-threshold-and-the-stranger-at-the-door',10,'The Fire, The Threshold, and The Stranger at the Door','A Time-Travel Adventure in the Ancient Anatolian Highlands','A mountain caravanserai and its town, with a shed workshop and farmhouse in Carolina as the frame story','Ancient Anatolian highlands (a Hittite-inspired mountain pass and guest-hall) and the Carver family''s home in the Carolinas','Ancient Anatolia, roughly Bronze Age / Hittite-era highlands, framed against a present-day family story','8-12',174,51638,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO books (slug,number,title,subtitle,setting_place,setting_region,era,age_range,page_count,word_count,updated_at) VALUES ('11-the-break-the-gold-and-the-palace-that-rose-again',11,'The Break, The Gold, and The Palace That Rose Again','A Time-Travel Adventure in Ancient Minoan Crete','An unwalled Bronze Age harbor town and its rising palace-complex, on an island of terraced hillsides, peak-shrines, and a mountain mending-cave','Ancient Minoan Crete (Aegean)','Bronze Age Aegean, Minoan civilization','9-12 (middle grade)',172,48909,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO books (slug,number,title,subtitle,setting_place,setting_region,era,age_range,page_count,word_count,updated_at) VALUES ('12-the-song-the-stars-and-the-country-that-remembers',12,'The Song, The Stars, and The Country That Remembers','A Time-Travel Adventure in Ancient Australia','a desert camp among the Aboriginal songline country of the Australian outback','Ancient Australia (Aboriginal songline country)','Ancient/timeless oral tradition (visited across a southern-hemisphere winter)','9-13',176,49012,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO books (slug,number,title,subtitle,setting_place,setting_region,era,age_range,page_count,word_count,updated_at) VALUES ('13-the-canoe-the-compass-and-the-shore-beyond-the-sky',13,'The Canoe, The Compass, and The Shore Beyond the Sky','A Time-Travel Adventure on the Ancient Pacific','A remote Pacific voyaging island and the open ocean between island waypoints','Ancient Polynesia / the deep Pacific','Ancient Pacific wayfinding era (pre-contact Polynesian voyaging societies)','8-12',174,49085,'2026-07-14T00:00:00.000Z');
