INSERT OR REPLACE INTO books (slug,number,title,subtitle,setting_place,setting_region,era,age_range,page_count,word_count,updated_at) VALUES ('15-the-center-the-maker-and-the-road-that-was-always-home',15,'The Center, The Maker, and The Road That Was Always Home','A Time-Travel Adventure at the Heart of the World','The Carver family home in Carolina, and the House at the Heart of the World (the mysterious center all fourteen prior journeys have been leading toward)','Rural Carolina, USA, and a symbolic gathering-place reached through the traveling cube — not a historical era but the culmination of the family''s travels across many lands and ages','Series finale — the summer after fourteen years of time-travel crossings, with a final journey to a place outside ordinary history','8-12 (middle grade)',164,48683,'2026-07-14T00:00:00.000Z');

INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq01','01-the-shed-the-cube-and-the-sands-of-time','faq-01','What is The Shed, The Cube, and The Sands of Time about?','It follows fourteen-year-old Simeon Carver and his sisters Beckah and Ellie, who discover a mysterious nine-sided cube buried beneath their family''s old backyard shed. The cube transports them from their 1986 summer to ancient Egypt during the construction of the Great Pyramid, where they must find a way home. It is a story about family, courage, and honest work as much as it is about time travel.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq02','01-the-shed-the-cube-and-the-sands-of-time','faq-02','Is this book part of a series?','Yes. It is Book One of The Cube Chronicles by Jeremy Tinder, a middle-grade historical time-travel series. The book ends with clear hints that the cube has more destinations to reveal in future installments.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq03','01-the-shed-the-cube-and-the-sands-of-time','faq-03','Do I need to read the books in order?','Yes, reading in order is recommended. This is the first book in the series and introduces the Carver family, the shed, and the cube itself, all of which future books build on.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq04','01-the-shed-the-cube-and-the-sands-of-time','faq-04','What age group is this book appropriate for?','It is written for middle-grade readers, roughly ages 8 to 12. The vocabulary is enriched with an asterisk-marked glossary of over 150 words, making it suitable for classroom or homeschool vocabulary building as well as independent reading.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq05','01-the-shed-the-cube-and-the-sands-of-time','faq-05','Where and when is the book set?','The story is framed in 1986 on Oakdale Road, the Carver family''s rural home, and its central adventure takes place in ancient Egypt around 2560 BCE, during the reign of Pharaoh Khufu and the building of the Great Pyramid of Giza.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq06','01-the-shed-the-cube-and-the-sands-of-time','faq-06','Is the historical setting based on a real civilization?','Yes. The book is set during the actual construction of the Great Pyramid of Giza in Old Kingdom Egypt. Back-matter sections called ''Did You Know?'' provide real historical facts, such as how pyramid workers were paid laborers rather than slaves, and details about Nile agriculture, ancient medicine, and desert windstorms called khamsins.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq07','01-the-shed-the-cube-and-the-sands-of-time','faq-07','Who are the main characters?','The story centers on the three Carver siblings: Simeon, a careful and hardworking fourteen-year-old; Beckah, a bookish problem-solver; and Ellie, an energetic and fearless younger sister. Their parents, Daniel and Elizabeth Carver, and Egyptian children named Khet and Nebet also play important roles.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq08','01-the-shed-the-cube-and-the-sands-of-time','faq-08','Does this book involve time travel or fantasy elements?','Yes. The central fantastical element is a mysterious nine-sided cube that transports the Carver children through history. Aside from the cube itself, the story stays grounded in realistic historical detail about ancient Egypt and 1980s family life.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq09','01-the-shed-the-cube-and-the-sands-of-time','faq-09','Is this book suitable for classroom or homeschool use?','Yes. It includes a ''Talk About It'' discussion guide with fifteen questions for families, classrooms, and homeschool groups, a glossary of vocabulary words, and a ''Did You Know?'' section of real historical facts about ancient Egypt and the Great Pyramid.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq10','01-the-shed-the-cube-and-the-sands-of-time','faq-10','What themes does the book explore?','The book explores family bonds, the value of honest work and craftsmanship, courage in unfamiliar situations, faith, responsibility, and the idea of trust between parent and child. A recurring line from the children''s father, that ''a man builds things right because that''s the foundation of who he is,'' threads through the whole story.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq11','01-the-shed-the-cube-and-the-sands-of-time','faq-11','Is the book frightening or violent?','There are a few tense adventure moments, including an encounter with a Nile crocodile and a desert windstorm, but there is no graphic violence or gore. The tone stays appropriate for middle-grade readers, emphasizing courage and problem-solving over danger for its own sake.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq12','01-the-shed-the-cube-and-the-sands-of-time','faq-12','Does the book contain religious or faith themes?','Yes. The Carver family''s Christian faith is woven into their everyday life, including prayer, Sunday church, and conversations with their pastor, and it shapes how the children process their time-travel experience. The story does not depict any deity as a visible character.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq13','01-the-shed-the-cube-and-the-sands-of-time','faq-13','How long is the book?','The book is approximately 127,754 words and 591 pages in paperback, organized into 30 chapters across four parts: Home, The Crossing, The Sands, and The Return.',0,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq14','01-the-shed-the-cube-and-the-sands-of-time','faq-14','What will readers learn about ancient Egyptian culture?','Readers learn about how the Great Pyramid was actually built by organized, paid laborers rather than slaves, what workers ate and how they lived, the importance of the Nile River, ancient games like Senet, early medicine, and surveying methods that predate Pythagoras.',0,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq15','01-the-shed-the-cube-and-the-sands-of-time','faq-15','What comes after this book in the series?','Book One is the start of The Cube Chronicles. The ending shows the cube''s ninth face forming a new symbol and hints that Beckah has begun decoding a message suggesting twenty or more destinations across history, setting up Book Two.',0,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq16','01-the-shed-the-cube-and-the-sands-of-time','faq-16','What did Simeon find buried under the old shed?','While tearing down the shed at his father''s request, Simeon discovers a strange nine-sided cube along with old tools and photographs buried beneath the shed''s floorboards, artifacts that turn out to be linked across multiple centuries.',1,15,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq17','01-the-shed-the-cube-and-the-sands-of-time','faq-17','How do the Carver children make it back home from ancient Egypt?','After weeks living among the pyramid workers and forming a bond with Khet and Nebet, the children use the same cube that brought them to Egypt to find their way back to Oakdale Road in 1986, guided in part by lessons learned from their father about steadiness and care.',1,16,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b01-faq18','01-the-shed-the-cube-and-the-sands-of-time','faq-18','Does Ellie face real danger during the adventure?','Yes. Ellie encounters a Nile crocodile while wading in the river with Nebet and, instead of running, chooses to walk calmly to safety while holding Nebet''s hand, an act that becomes a defining moment of courage for her character.',1,17,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq01','02-the-compass-the-coast-and-the-edge-of-the-world','faq-01','What is ''The Compass, The Coast, and The Edge of the World'' about?','It''s the second book in The Cube Chronicles, in which the Carver children are pulled by their mysterious cube into ancient Athens during the Golden Age, right as the Parthenon is being built.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq02','02-the-compass-the-coast-and-the-edge-of-the-world','faq-02','Do I need to read Book 1 first?','Yes, it''s strongly recommended. Book 2 picks up three weeks after the events of Book 1 (set in ancient Egypt) and references that trip, the cube''s discovery, and the children''s growth from it throughout.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq03','02-the-compass-the-coast-and-the-edge-of-the-world','faq-03','Where and when does this book take place?','The story is set in Athens, Greece, during the Golden Age of the 5th century BC, while the Parthenon is under construction on the Acropolis under the leadership of Pericles.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq04','02-the-compass-the-coast-and-the-edge-of-the-world','faq-04','Who are the main characters?','The three Carver siblings — Simeon (14, the builder), Beckah (12, the healer and linguist), and Ellie (9, the voice) — along with their parents Daniel and Elizabeth Carver back home in North Carolina.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq05','02-the-compass-the-coast-and-the-edge-of-the-world','faq-05','What age group is this book appropriate for?','It''s written for middle-grade readers, roughly ages 8 to 12, with rich vocabulary and historical detail that also appeals to strong younger readers and adults who enjoy family-friendly historical fiction.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq06','02-the-compass-the-coast-and-the-edge-of-the-world','faq-06','Is this book based on real history?','Yes. The setting draws on real historical details of classical Athens, including the construction of the Parthenon, the Athenian agora, Doric architecture, Greek theater, and the intellectual culture of the era, including a young stonecutter named Sokrates.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq07','02-the-compass-the-coast-and-the-edge-of-the-world','faq-07','How does the time travel work in this series?','An ancient, nine-sided cube found beneath the Carver family''s shed glows and transports the children through history when one of its symbols finishes forming. It has already taken them to ancient Egypt and, in this book, to ancient Greece.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq08','02-the-compass-the-coast-and-the-edge-of-the-world','faq-08','Is this book appropriate for a classroom read-aloud?','Yes. It pairs adventure fiction with real historical content about ancient Greece — architecture, philosophy, theater, and civic life — making it a natural companion to a classical civilizations unit.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq09','02-the-compass-the-coast-and-the-edge-of-the-world','faq-09','What themes does the book explore?','Family, honesty, courage, and the idea that true craftsmanship combines function with beauty — echoed through the children''s parallel lessons in Egypt (endurance) and Greece (beauty) and their father''s practical building philosophy back home.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq10','02-the-compass-the-coast-and-the-edge-of-the-world','faq-10','Is there anything frightening or violent in this book?','No. The book is family-friendly with no graphic violence or gore. There is some tension from crowded, unfamiliar surroundings, physical labor, and a family''s fear of secrets, but nothing intense or scary for its middle-grade audience.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq11','02-the-compass-the-coast-and-the-edge-of-the-world','faq-11','Does the book include faith or religious themes?','Yes, in a warm, natural way. The Carver family is shown praying and reading Scripture together at home, and their faith is portrayed as part of the emotional and moral foundation the children carry with them through their travels.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq12','02-the-compass-the-coast-and-the-edge-of-the-world','faq-12','How long is the book?','It''s approximately 107,900 words, or about 417 pages in the KDP paperback edition — a substantial read for confident middle-grade readers.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq13','02-the-compass-the-coast-and-the-edge-of-the-world','faq-13','What can kids learn about ancient Greek culture from this book?','Readers get an immersive look at daily life in classical Athens: the bustling agora, Doric temple construction on the Acropolis, Greek theater and performance, early philosophy, and the social norms of the time, including the restricted roles of women.',0,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq14','02-the-compass-the-coast-and-the-edge-of-the-world','faq-14','What happened just before this book, at the end of Book 1?','The Carver children had just returned from their first crossing to ancient Egypt, where they helped build near the Great Pyramid and formed bonds with an Egyptian family. Book 2 opens three weeks later as the cube begins to activate again.',0,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq15','02-the-compass-the-coast-and-the-edge-of-the-world','faq-15','What is set up for the next book in the series?','By the end of the book, the cube''s ninth face is already forming a new symbol, and the family agrees all five of them will be present for the next crossing, setting up Book 3''s journey to a new, still-unspecified civilization.',0,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq16','02-the-compass-the-coast-and-the-edge-of-the-world','faq-16','Do the Carver parents find out about the cube in this book?','Yes. Although Daniel and Elizabeth don''t witness the full truth of time travel firsthand, by the story''s end they''ve moved from suspicion to full awareness, and they plan to be present in the yard for the next crossing.',1,15,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq17','02-the-compass-the-coast-and-the-edge-of-the-world','faq-17','Does Simeon leave a lasting mark on a real historical monument?','Yes — under the mentorship of a master sculptor, Simeon carves a galloping horse into the Parthenon frieze, a piece of the actual historical monument that (in the present day) resides in the British Museum.',1,16,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b02-faq18','02-the-compass-the-coast-and-the-edge-of-the-world','faq-18','Does Ellie get to use her big personality in this book?','Yes — Ellie''s larger-than-life voice, which gets her in trouble at school, becomes an asset when she performs before a massive crowd in an ancient Athenian theater, discovering that the very thing adults ask her to quiet down is actually a gift.',1,17,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq01','03-the-river-the-seal-and-the-language-of-silence','faq-01','What civilization does this book visit?','The Carver children travel to Mohenjo-daro, a major city of the ancient Indus Valley Civilization, around 2600–1900 BC, in what is now Pakistan and northwest India.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq02','03-the-river-the-seal-and-the-language-of-silence','faq-02','Do the parents know about the cube''s travels in this book?','Yes. Unlike earlier books, Daniel and Elizabeth Carver now know the family''s secret and choose to accompany their children to the shed and wait together while the children cross through time.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq03','03-the-river-the-seal-and-the-language-of-silence','faq-03','Is this book appropriate for a sensitive child?','Yes, it is written for middle-grade readers with no graphic violence; the only tense moments involve a flooded courtyard and general references to disease from unclean water, handled in an educational, non-graphic way.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq04','03-the-river-the-seal-and-the-language-of-silence','faq-04','What historical topics does this book teach?','It covers Indus Valley urban planning, standardized brick construction, citywide drainage and sanitation, the undeciphered Indus script, seal-carving, standardized weights and measures, granaries, and the Great Bath.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq05','03-the-river-the-seal-and-the-language-of-silence','faq-05','Who are the main new characters the Carver children meet?','They meet Ravi, an apprentice drain-engineer; Ashwin, the master engineer who tests Simeon; Devak, a master seal-carver; his daughters Mira and Priya, who teach Beckah and Ellie their crafts; and Padma, a city healer.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq06','03-the-river-the-seal-and-the-language-of-silence','faq-06','What does each Carver child learn or do in Mohenjo-daro?','Simeon apprentices with the city''s drain engineer and repairs a real household drain; Beckah learns to read the ancient Indus script with Mira''s help; Ellie trains as a seal-carver under Priya, learning patience and precision.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq07','03-the-river-the-seal-and-the-language-of-silence','faq-07','Is the Indus script actually undeciphered in real history?','Yes—the real Indus script has never been deciphered by modern scholars, which the book uses as the basis for Beckah''s storyline of learning to read it directly from the people who used it.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq08','03-the-river-the-seal-and-the-language-of-silence','faq-08','Does the book portray God or ''the Maker'' as a visible character?','No. Faith is present through the Carver family''s prayers, Bible readings, and conversations about the ''Builder'' behind the cube''s curriculum, but the Maker is never shown or depicted directly.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq09','03-the-river-the-seal-and-the-language-of-silence','faq-09','How does this book fit into the Cube Chronicles series order?','It is Book 3, following crossings to ancient Egypt and ancient Greece, and continues the family''s journey along a thirty-four-destination spiral tied to a growing nine-sided cube.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq10','03-the-river-the-seal-and-the-language-of-silence','faq-10','What is the title referring to?','The river is the Indus, whose floods shaped the valley; the seal refers to the carved stone seals bearing the Indus script; and the ''language of silence'' reflects the book''s theme that the civilization''s quiet, unglamorous infrastructure—not monuments—was its truest form of expression.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq11','03-the-river-the-seal-and-the-language-of-silence','faq-11','Is prior knowledge of Books 1 and 2 required to understand this book?','No, the book recaps key family history, but readers will appreciate returning references to Egypt and Greece more fully if they''ve read the earlier books.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq12','03-the-river-the-seal-and-the-language-of-silence','faq-12','Does the book include any real archaeological sites or facts?','Yes, it draws on real features of Mohenjo-daro such as its citadel mound, the Great Bath, granary, standardized brick sizes, and its status as an undeciphered ancient script—dramatized through fictional characters and events.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq13','03-the-river-the-seal-and-the-language-of-silence','faq-13','What happens at the end of the book regarding the family''s larger mission?','In a hidden chamber reached through the city''s drainage system, Simeon and Beckah decode a builders'' message confirming that the curriculum spans thirty-four destinations over about eight and a half years, and that once the central ''lock'' opens, ''the path does not close.''',1,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq14','03-the-river-the-seal-and-the-language-of-silence','faq-14','Does Ellie succeed at seal-carving by the end of the book?','Yes, after multiple failed and cracked attempts, Ellie completes her own seal under Priya''s guidance, having learned to trade her usual boldness for the patience the craft demands.',1,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b03-faq15','03-the-river-the-seal-and-the-language-of-silence','faq-15','How does the book end and set up Book 4?','The Carver family celebrates New Year''s Eve 1986 together, and Beckah reports the ninth face has already begun forming its fourth symbol, meaning a new crossing to a fourth civilization is expected within six to eight weeks.',1,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq01','04-the-knot-the-flame-and-the-bones-that-speak','faq-01','What civilization does Book 4 take the Carver children to?','A mountain village above the Yellow River in ancient China, around 1900 BC, known for silk weaving, bronze casting, and oracle-bone divination.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq02','04-the-knot-the-flame-and-the-bones-that-speak','faq-02','Do I need to read the first three Cube Chronicles books before this one?','It helps but isn''t required. Book 4 recaps the cube''s rules and the family''s prior crossings (Egypt, Greece, and the Indus Valley) as the children compare this trip to earlier ones.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq03','04-the-knot-the-flame-and-the-bones-that-speak','faq-03','What does each Carver sibling learn or do in this book?','Simeon apprentices with a village bronze-master to build and fire his own furnace; Beckah studies the village''s knotted-cord counting system and an oracle-bone diviner''s practice; Ellie learns a generations-old song on a bone flute.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq04','04-the-knot-the-flame-and-the-bones-that-speak','faq-04','Is this book historically accurate?','The novel is grounded in real historical practices of early Bronze Age China, including bronze furnace technology, oracle bone divination tied to agricultural planning, silk production, and knotted-cord record-keeping, presented through the children''s firsthand observation and questions.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq05','04-the-knot-the-flame-and-the-bones-that-speak','faq-05','Is the oracle-bone divination scene appropriate for kids?','Yes. It''s presented as a real historical practice the children observe respectfully and discuss thoughtfully, weighing what the diviner might be interpreting versus predicting from experience. It is not depicted as anything supernatural threatening to the children.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq06','04-the-knot-the-flame-and-the-bones-that-speak','faq-06','Does this book contain violence or scary content?','No graphic violence. The furnace work involves real heat and danger as part of the craft lesson, but no characters are harmed. Tension comes from learning difficult skills and understanding a new culture, not from combat or peril.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq07','04-the-knot-the-flame-and-the-bones-that-speak','faq-07','Is the cube itself ever explained in this book?','The cube continues to reveal itself gradually. In this book its ninth face grows a new crystalline configuration with a cold blue-white glow tied to the destination''s element, fire, continuing the pattern established in earlier books.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq08','04-the-knot-the-flame-and-the-bones-that-speak','faq-08','Is faith a big part of this book?','Yes. The Carver family''s Christian faith, prayer, and Bible readings are woven throughout, especially in father Daniel''s reflections connecting the furnace''s transforming fire to spiritual themes of renewal and purpose.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq09','04-the-knot-the-flame-and-the-bones-that-speak','faq-09','Is the Maker or God shown directly in the story?','No. The family speaks of the Builder/Maker and prays, but the Maker is never depicted or made visible; faith is expressed through the family''s words, traditions, and reflections rather than any direct appearance.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq10','04-the-knot-the-flame-and-the-bones-that-speak','faq-10','What age group is this book best suited for?','Ages 8 to 12, consistent with the rest of the Cube Chronicles series, though older middle-grade readers who enjoy detailed historical description will also find plenty to like.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq11','04-the-knot-the-flame-and-the-bones-that-speak','faq-11','Who are Mei, Hua, Zhou, and Liang?','They are villagers the Carver children befriend and learn from: Mei teaches Ellie a mountain flute song, Hua teaches Beckah the knotted-cord record system, Zhou is the bronze-master who trains Simeon, and Liang is Zhou''s apprentice who helps translate.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq12','04-the-knot-the-flame-and-the-bones-that-speak','faq-12','How long is the book?','About 79,700 words, roughly 314 pages in the KDP paperback edition, across 30 chapters in four parts.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq13','04-the-knot-the-flame-and-the-bones-that-speak','faq-13','Would this book work well for a classroom or homeschool unit on ancient China?','Yes. It covers bronze-casting technology, oracle bone divination, silk production, and early record-keeping systems in vivid, accurate detail, making it a strong companion to a unit on early Bronze Age China.',0,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq14','04-the-knot-the-flame-and-the-bones-that-speak','faq-14','Does Simeon succeed in building his furnace?','Yes — after failed early attempts and patient correction from Zhou, Simeon eventually builds a furnace capable of holding the heat needed for bronze casting, marking his mastery of the fourth civilization''s central craft.',1,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq15','04-the-knot-the-flame-and-the-bones-that-speak','faq-15','What does Ellie bring home from her time with Mei?','Ellie learns the complete mountain song passed down through generations of mothers in Mei''s family, and carries the bone flute itself back to the Carver home in 1987, where she can still play the ancient melody.',1,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b04-faq16','04-the-knot-the-flame-and-the-bones-that-speak','faq-16','Does the book end with a cliffhanger?','Not a cliffhanger in the danger sense — the fourth crossing resolves safely and the family returns home. But the ending shows the cube''s ninth face already growing a fifth configuration, setting up the next civilization and book.',1,15,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq01','05-the-shore-the-flame-and-the-shape-of-water','faq-01','Where and when is this book set?','The fifth book takes the Carver children to a Jōmon-period fishing village on a black-sand Pacific coast in ancient Japan, around 2500 BC.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq02','05-the-shore-the-flame-and-the-shape-of-water','faq-02','Do I need to read the earlier books first?','It helps but isn''t strictly required. Book 5 references earlier crossings (Egypt, Greece, the Indus Valley, and China) and callbacks like Mei''s mountain song, but the Japan storyline stands on its own.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq03','05-the-shore-the-flame-and-the-shape-of-water','faq-03','Who are the Carver children in this book?','Simeon (15), Beckah, and Ellie (10) are the three siblings who travel through the cube; their parents, Daniel and Elizabeth, stay behind in Oakdale, North Carolina.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq04','05-the-shore-the-flame-and-the-shape-of-water','faq-04','What new friends do the children make in this book?','Simeon befriends Hana, a young potter; Ellie learns drumming from Kai; and Beckah exchanges keepsakes with Yua, a cord-maker. The healer Chiyo and fisherman Oto also feature prominently.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq05','05-the-shore-the-flame-and-the-shape-of-water','faq-05','Is this book appropriate for younger middle-grade readers?','Yes. It''s written for ages 8-12 with no profanity or romance and only mild, non-graphic peril, such as a fisherman''s injured shoulder.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq06','05-the-shore-the-flame-and-the-shape-of-water','faq-06','Does the book include religious content?','Yes. Like the rest of the series, the Carver family''s Christian faith is woven throughout, including mealtime prayers and Scripture readings, and the story draws a parallel between a potter mending broken pottery and spiritual restoration.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq07','05-the-shore-the-flame-and-the-shape-of-water','faq-07','Is ''the Maker'' shown directly in the story?','No. The Maker is referenced as a guiding, providential presence in the family''s faith and conversations but is never depicted or shown visibly on the page.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq08','05-the-shore-the-flame-and-the-shape-of-water','faq-08','What historical topics does this book teach?','Readers learn about Jōmon-period pottery techniques (flame-style ceramics and cord-marking), traditional drumming, dogū clay figures used in healing rituals, and early herbal medicine such as willow bark for pain relief.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq09','05-the-shore-the-flame-and-the-shape-of-water','faq-09','How does the time-travel cube work in this book?','The cube reveals a new glowing configuration for each destination; in this book its warm amber-orange glow and rising heat signal a fire-and-water theme, guiding the children to the correct time period and location.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq10','05-the-shore-the-flame-and-the-shape-of-water','faq-10','What skill does Ellie learn in Japan?','Ellie learns village drumming and rhythm from a boy named Kai, and by the end blends it with the mountain flute song she learned from Mei in an earlier book.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq11','05-the-shore-the-flame-and-the-shape-of-water','faq-11','What does Beckah study during this crossing?','Beckah documents Jōmon medicine, comparing practical herbal remedies to the symbolic use of dogū clay figures in healing, and reflects on this contrast in her field journal.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq12','05-the-shore-the-flame-and-the-shape-of-water','faq-12','Is this the final book in the Cube Chronicles?','No. The book closes noting that a sixth cube configuration is already forming, signaling more crossings and destinations ahead in the series.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq13','05-the-shore-the-flame-and-the-shape-of-water','faq-13','Would this book work well for a classroom read-aloud on ancient civilizations?','Yes, it pairs an engaging adventure story with grounded details about Jōmon Japan''s pottery, tools, and community life, making it useful alongside a world-history unit.',0,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq14','05-the-shore-the-flame-and-the-shape-of-water','faq-14','Does the injured fisherman, Oto, fully recover in the story?','The book shows him being treated with herbal medicine and a symbolic dogū ritual that eases his fear, though it is clear his physical healing will still take weeks beyond the story''s timeframe.',1,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq15','05-the-shore-the-flame-and-the-shape-of-water','faq-15','What happens with the exchanged gifts between the children at the end?','Ellie gives Kai a Pacific beach stone and receives his own drumsticks in return, while Beckah and Yua trade cord and clay tokens bearing each other''s identifying marks, symbolizing their cross-time friendships.',1,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b05-faq16','05-the-shore-the-flame-and-the-shape-of-water','faq-16','Does the book end with a cliffhanger?','Not a dramatic cliffhanger, but it ends with a strong forward hint: Daniel notes a new, sixth cube configuration is forming, promising another destination in the next book.',1,15,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq01','06-the-river-the-wheel-and-the-city-of-the-moon','faq-01','What civilization does Book 6 visit?','The Carver family travels to ancient Sumer, in the city of Ur on the Tigris-Euphrates river delta, home to some of the world''s first cities.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq02','06-the-river-the-wheel-and-the-city-of-the-moon','faq-02','Is this book part of a series, and do I need to read the others first?','Yes, it is Book 6 of The Cube Chronicles. It can be read as a standalone adventure, but returning readers will recognize ongoing family traditions and callbacks to earlier crossings (Egypt, the Indus Valley, China, Japan, and more).',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq03','06-the-river-the-wheel-and-the-city-of-the-moon','faq-03','Who are the main characters?','The Carver family: Daniel (a builder), Elizabeth (mother), and their children Simeon, Beckah, and Ellie. In Sumer they befriend Igmil (a canal apprentice), Ur-Nin (a canal-master), Shara (a self-taught scribe girl), and Dudu (a young temple musician).',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq04','06-the-river-the-wheel-and-the-city-of-the-moon','faq-04','What is the ''sixth configuration'' of the cube?','It''s the cube''s green-gold, rippling glow that signals the family''s sixth destination—a river-delta civilization built around irrigation, distinct from the fire, water, and light patterns of prior crossings.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq05','06-the-river-the-wheel-and-the-city-of-the-moon','faq-05','What historical topics does this book teach?','Readers learn about Sumerian irrigation (canals, the shaduf), cuneiform writing and scribe schools, bitumen as a building material, the true arch, the seeder plow, ziggurats, and ancient Mesopotamian music.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq06','06-the-river-the-wheel-and-the-city-of-the-moon','faq-06','Is the book appropriate for a classroom or library collection?','Yes. It is a family-friendly, middle-grade historical adventure with strong educational content on ancient Mesopotamia, suitable for classroom units on early civilizations or library shelves alongside other historical fiction.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq07','06-the-river-the-wheel-and-the-city-of-the-moon','faq-07','Does this book contain any violence or scary content?','No graphic violence. There is everyday manual-labor peril (working near rivers and canals, tar burns from bitumen work) typical of historical craft apprenticeship, handled in a mild, age-appropriate way.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq08','06-the-river-the-wheel-and-the-city-of-the-moon','faq-08','Is there religious content in this book?','Yes. As in the rest of the series, the Carver family is a Christian family who prays and reflects on faith. This volume ties their visit to Ur directly to the biblical account of Abraham, who is said to have come from ''Ur of the Chaldees.''',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq09','06-the-river-the-wheel-and-the-city-of-the-moon','faq-09','What is ''the Maker'' and is it shown in the book?','References to a divine Maker/God appear in the family''s prayers and reflections throughout the series, but the Maker is never depicted or shown visibly on the page.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq10','06-the-river-the-wheel-and-the-city-of-the-moon','faq-10','What craft does Simeon learn in this book?','Simeon apprentices in Sumerian canal-keeping and water management, learning to work with bitumen (natural tar) as mortar and waterproofing, build reed boats, and construct a true mudbrick arch.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq11','06-the-river-the-wheel-and-the-city-of-the-moon','faq-11','What does Ellie learn in Ur?','Ellie learns to play the lyre from a young temple musician named Dudu, discovering how one instrument can carry melody, rhythm, and harmony together.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq12','06-the-river-the-wheel-and-the-city-of-the-moon','faq-12','What is the ''sixth wisdom'' the father teaches in this book?','Daniel''s sixth building wisdom is ''build the builder''—teaching an apprentice so that what you build outlives you, mirrored in the recursive, self-sustaining systems (canals, seed crops) the family studies in Sumer.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq13','06-the-river-the-wheel-and-the-city-of-the-moon','faq-13','How long is the book, and how many chapters and parts does it have?','The River, The Wheel, and The City of the Moon runs about 52,000 words (198 pages in paperback), organized into 30 chapters across four parts: The Delta, The Wheel, The Deep, and The Return.',0,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq14','06-the-river-the-wheel-and-the-city-of-the-moon','faq-14','Does this book end on a cliffhanger?','It closes on the family''s usual grateful, reflective return home, but ends with a clear hint that a seventh cube configuration (''tooth'') is already forming, setting up the next book in the series.',0,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq15','06-the-river-the-wheel-and-the-city-of-the-moon','faq-15','What happens to Shara, the scribe girl Beckah befriends?','Shara, who had been secretly teaching herself cuneiform outside the scribe school walls, gives Beckah a keepsake tablet and a cylinder seal that the Carver family brings home and displays on their shelf, and Beckah continues corresponding with her through the visit.',1,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq16','06-the-river-the-wheel-and-the-city-of-the-moon','faq-16','Does the family encounter anything connected to the biblical Abraham?','Yes—the family realizes they are visiting Ur during the era associated with Abraham''s family, and Daniel reflects at length in prayer on the biblical ''Get thee out'' call, though Abraham himself does not appear as a character on the page.',1,15,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b06-faq17','06-the-river-the-wheel-and-the-city-of-the-moon','faq-17','What keepsakes do the Carvers bring home from Sumer?','They return with a fired brick stamped in cuneiform with the family''s names, Shara''s practice tablet, and a cylinder seal, all added to the family''s growing ''shelf'' of relics from each civilization.',1,16,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq01','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-01','What civilization does Book 7 take the Carver family to?','The family travels to a terraced village high in the ancient Andes, in a civilization organized around rope-bridge engineering and altitude survival, evoking the Inca era.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq02','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-02','Do I need to read the previous six books to understand this one?','No. Each Cube Chronicles book stands alone with a new destination, though returning readers will recognize the Carver family''s ongoing traditions and the developing pattern of the cube''s configurations.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq03','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-03','What craft does Simeon learn in this book?','Simeon apprentices under Mama Quri, the village''s rope-mistress, to learn cable-making for the suspension bridge — a demanding trade of sustained tension and endurance, different from the trades (stonework, metalwork) he''s learned in prior books.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq04','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-04','Is this book appropriate for a classroom read-aloud?','Yes. It is written for middle-grade readers with family-friendly content, though it includes a sensitively handled off-page death from an altitude-related accident, which teachers may want to preview.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq05','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-05','What historical or cultural topics does the book teach?','Readers learn about Andean rope-bridge construction, khipu (knotted-cord) record-keeping, terrace farming, the potato''s importance to Andean civilization, and the challenges of living at high altitude.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq06','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-06','Who is Mama Quri?','Mama Quri is the village''s rope-mistress, the keeper who judges, maintains, and directs the rebuilding of the community''s suspension bridge cables, and who mentors Simeon.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq07','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-07','Does ''the Maker'' (the cube''s origin) appear directly in this book?','No. As in the rest of the series, the Maker is never shown directly; the family experiences the cube''s guidance and meaning through configurations, symbols, and reflection rather than any visible appearance.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq08','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-08','What is a khipu, and how is it used in the story?','A khipu is a knotted cord used by Andean civilizations to record numbers and information. In the book, a keeper named Sami explains that the khipu ''remembers'' truthfully what people might forget or misstate.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq09','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-09','How does the family cope with high altitude in the story?','Elizabeth insists the family pace themselves, rest often, drink more water, and pack warm layers and eye protection, since altitude sickness brings headaches, fatigue, and shortness of breath that ease only with time.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq10','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-10','What is the family''s seventh ''wisdom'' or lesson in this book?','Daniel''s lesson is ''Build the bridge before you need to cross'' — the idea that meaningful support and preparation must be built ahead of time, out of love, before the need for it ever arrives.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq11','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-11','Is the series religious?','The books include gentle expressions of Christian faith through the Carver family''s evening prayers and reflections, woven into the adventure and historical learning rather than presented as overt teaching.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq12','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-12','What age group is this book written for?','The Cube Chronicles is written for middle-grade readers, generally ages 8 to 12, and is suitable for family read-aloud.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq13','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-13','How long is this book?','The Rope, The Ridge, and The Roof of the World is approximately 49,771 words and 175 pages in the KDP paperback edition.',0,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq14','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-14','Does a character die in this book?','Yes — a village boy dies from an altitude-related cause partway through the story. His death is handled with care through community mourning and Mama Quri''s reflections on grief and endurance, without graphic detail.',1,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq15','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-15','What does the family discover about the cube''s larger pattern in this book?','They realize the builders across history are not people traveling toward a distant destination but are themselves becoming spans of one endless bridge woven across time, meaning there is ''no far side'' left to reach — only more of the bridge to build.',1,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b07-faq16','07-the-rope-the-ridge-and-the-roof-of-the-world','faq-16','How does Elizabeth''s personal history connect to the village elder Mama Quri?','Elizabeth recognizes her own experience of carrying grief and responsibility after her mother''s death in Mama Quri''s teaching that grief and work must be twisted together, like cable, to hold weight that would otherwise break a person.',1,15,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq01','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-01','What civilization does Book 8 take the Carver family to?','An ancient Amazonian rainforest civilization — a dispersed, four-thousand-year-old ''food forest'' city of raised causeways, fish weirs, and manufactured black-earth soil, home to roughly thirty thousand people living without a central settlement or writing system.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq02','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-02','Do the Carver children travel together in this book?','Yes. As in every Cube Chronicles book, Simeon, Beckah, and Ellie Carver travel together through the cube, each focusing on different lessons of the crossing while their parents, Daniel and Elizabeth, support them from home.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq03','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-03','What is ''terra preta'' and why does it matter in this story?','Terra preta, or ''black earth,'' is a real-world type of rich, human-made Amazonian soil created over generations from charcoal, bone, ash, and food waste. In the book, Simeon apprentices under a forest-tender named Iara to learn how this living soil is made and fed, and it becomes the story''s central symbol of tending versus finishing.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq04','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-04','What is the ''eighth wisdom'' Daniel Carver receives this crossing?','''Tend what you plant.'' Unlike the previous seven wisdoms, which were all about building well, this one is about caring for a finished thing so it stays alive — introducing the book''s theme that a made thing left unattended eventually dies.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq05','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-05','Is this book part of a series, and do I need to read the others first?','It''s Book 8 of The Cube Chronicles. Each book is a self-contained historical adventure, though returning readers will recognize the ongoing ''wisdom'' and ''warning'' threads that build across the series.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq06','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-06','Is the story appropriate for sensitive young readers?','Yes, with light caveats. It''s family-friendly and free of violence or romance, but it does reference a historical epidemic that took a character''s husband and sons (mentioned, not shown) and includes a tense scene of wading through a flooded cave. Themes of grief are handled with warmth and hope.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq07','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-07','Does the cube ever explain who built it or who ''the Maker'' is?','The family continues to wonder about the builders behind the cube and its chambers, and they draw spiritual parallels to their faith, but neither the cube''s makers nor the divine figure they discuss is ever shown or physically depicted — the mystery remains open by design.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq08','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-08','What real historical/scientific ideas does this book teach?','It introduces real archaeological findings about precolumbian Amazonia: engineered ''dark earth'' soils, raised causeway roads, managed food forests, fish weir systems, and evidence that the Amazon supported large, sophisticated, non-urban-in-the-traditional-sense populations without stone monuments or writing.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq09','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-09','How does this book fit into a classroom or homeschool unit on ancient civilizations?','It works well alongside units on the Amazon, agricultural history, or ecology, since it dramatizes real anthropological findings about Amazonian soil science and settlement patterns in an accessible narrative, paired with discussion-ready themes about community and stewardship.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq10','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-10','Does Ellie''s storyline focus on something specific this time?','Yes. Guided by a village girl named Yara, Ellie learns to listen for the forest''s layered birdsong and to find the ''gap'' where a human voice fits into that ongoing chorus, tying into her recurring role as the family''s listener.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq11','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-11','What does Elizabeth Carver''s seed-packing tradition signify?','For the first time in eight crossings, Elizabeth sends her children out carrying garden seeds from home instead of only bringing things back — a small gesture that becomes central once the crossing''s destination turns out to be built around gardening and giving.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq12','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-12','Who is Tapira, and what role does she play?','Tapira is the village''s elder forest-mother and seed-keeper. She survived a devastating epidemic that took her husband and sons by throwing herself into planting rather than despair, and she becomes Simeon''s teacher and the source of the book''s key insight about finishing versus tending.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq13','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-13','What is the ''sixth warning'' found in this book, and how does it change the family''s understanding of the whole series?','Deep in a flooded cave, Beckah finds a warning grown into living moss: ''The builder does not finish. The builder feeds. What is finished is dead. What is fed lives.'' It reframes all seven prior crossings — the family realizes the series'' warnings have been moving them from ideas about a fixed path toward a living, ongoing relationship they must keep feeding rather than complete.',1,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq14','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-14','What gift does Simeon bring home from this crossing, and how is it different from past souvenirs?','Instead of a finished tool like a level or a splice, Tapira gives Simeon a pouch of living dark earth, and Iara gives him a terra preta starter culture — living gifts meant to be fed and grown rather than kept as static keepsakes, which the family plants in their own Carolina garden.',1,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b08-faq15','08-the-seed-the-soil-and-the-cities-beneath-the-green','faq-15','How does the book end, and what does it suggest is coming next?','The family reflects that their eight years of crossings have filled a metaphorical ''shelf'' of finished treasures, but concludes that the deeper work ahead is ''ground,'' not shelf — living things that must be fed forever. The closing lines hint that a ninth crossing is already forming.',1,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq01','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-01','What is the ninth book in the Cube Chronicles series about?','The Rain, The Cedar, and The Rivers of Silver sends the three Carver children through the cube to an ancient Pacific salmon coast, where cedar-plank great houses and enormous yearly salmon runs create a culture of abundance built around giving rather than keeping.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq02','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-02','Do I need to read the first eight books to understand this one?','No. Each book is a self-contained adventure to a new place and time, though returning readers will appreciate the ongoing thread of the family''s yearly cube journeys and the accumulating ''wisdoms'' Daniel Carver has learned across all nine trips.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq03','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-03','Who are the main characters in this book?','The story follows siblings Beckah, Simeon, and Ellie Carver on the salmon coast, alongside their parents Daniel and Elizabeth back home in Carolina, and coast characters including master carver Nulis, rememberer Tsana, interpreter Miku, and clan mother Awina.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq04','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-04','What historical culture and time period does this book depict?','The book is set among an ancient Pacific Northwest Coast Indigenous salmon-culture society, featuring cedar-plank great houses, carved crests, and a subsistence economy centered on the seasonal salmon run.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq05','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-05','Is this book appropriate for middle-grade readers?','Yes. It is written for roughly ages 8-12, with family-friendly content, no graphic violence, and themes of generosity, gratitude, and cultural respect explored through an adventure narrative.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq06','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-06','Does the book explain what the mysterious cube actually is?','No. Consistent with the whole series, the cube''s origin and the being behind it (referred to only as ''the Maker'' or ''the builders'') are never shown or fully explained; the children instead find clues and warnings that deepen the mystery.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq07','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-07','What does Simeon learn from the master carver Nulis?','Simeon apprentices in cedar carving and canoe-making, and Nulis repeatedly asks him a probing ''season-question'' about the true purpose of any made object, pushing Simeon toward the idea that things are made to be given away, not kept.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq08','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-08','What is the ''guest pot'' mentioned in the book?','The guest pot is a longstanding Carver family tradition in which Elizabeth serves the very first portion of every meal to guests before her own children are served, symbolizing the family''s commitment to hospitality and giving.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq09','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-09','What role does Beckah play in this installment?','Beckah continues her role as the family''s chronicler, this time learning from Tsana, a coast rememberer, about how oral history, memory, and formline art are used to preserve a family''s story without written language.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq10','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-10','Does Ellie get into any trouble with the coast''s customs?','Ellie unknowingly learns and sings a song that belongs exclusively to another family under the coast''s strict song-ownership customs, leading to a tense but ultimately respectful resolution in front of the whole great house.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq11','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-11','What themes about wealth and generosity does the book explore?','The book contrasts wealth that is hoarded with wealth that is given away, using the coast''s abundant salmon runs, crest-ownership customs, and firstfruits-style ceremonies to show generosity as a discipline that keeps a family or people healthy.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq12','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-12','Are there any educational or classroom uses for this book?','Yes. Teachers can use it to introduce Pacific Northwest Coast Indigenous culture, salmon-based subsistence economies, oral history and memory-keeping traditions, and discussions of gratitude and community giving.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq13','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-13','Is there any religious content in the book?','Yes, mild and reflective. Daniel Carver draws a parallel between the coast''s firstfruits-style offerings and biblical firstfruits teachings, framing giving as a spiritual discipline; the content is presented gently within the family''s own faith reflections rather than as instruction to the reader.',0,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq14','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-14','How does the book end, and does it set up a tenth book?','(Spoiler) The family returns home changed by what they learned, and Elizabeth gives away the actual guest pot itself — the physical object, not just the practice — to a new family on their street, passing on its rule. The narration then notes ''the tenth tooth is growing,'' confirming a tenth cube journey is coming.',1,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq15','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-15','What happens with the ''seventh warning'' referenced in the book?','(Spoiler) A carved warning inside the cube''s living archive tells the family ''the carrier does not keep; the gift is the crossing.'' Clan mother Awina reinterprets it not as a rebuke but as a ''commissioning,'' urging the family to remain open-handed as their responsibilities grow across future crossings.',1,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq16','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-16','What does Daniel Carver''s ninth ''wisdom'' turn out to be?','(Spoiler) Watching Elizabeth serve the guest pot before her own children finally reveals it to him: ''Build it to give it away'' — the idea that everything built, taught, or made across the family''s nine journeys was always meant to be handed to someone else.',1,15,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b09-faq17','09-the-rain-the-cedar-and-the-rivers-of-silver','faq-17','Is the cube or its maker ever shown directly in this book?','No. As throughout the series, the being behind the cube is never depicted or seen — only implied through warnings, carvings, and the effects of its light.',0,16,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq01','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-01','What is the exact title of book 10 in The Cube Chronicles?','The Fire, The Threshold, and The Stranger at the Door, with the descriptor ''A Time-Travel Adventure in the Ancient Anatolian Highlands,'' both confirmed in the manuscript''s front matter.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq02','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-02','Where and when does this installment take place?','The children cross into the ancient Anatolian highlands, arriving in a bitter winter at a mountain caravanserai (guest-hall) and its town, a setting inspired by ancient hospitality codes such as those recorded on Hittite-era law tablets.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq03','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-03','Do I need to read the first nine books to understand this one?','No, the crossing and setting stand on their own, but Beckah''s running study of writing systems and the family''s ''wisdoms'' build on lessons from earlier books, so longtime readers will notice deeper callbacks and payoffs.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq04','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-04','Who are the main characters in this book?','The three Carver children — Beckah (the family''s historian and scribe), Ellie (age twelve, a singer), and Simeon (age seventeen, a builder) — along with their parents Daniel and Elizabeth back home, and new highland friends Kubaba, Sappi, Halki, and Tarhun.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq05','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-05','What is the cube and how does it work in this book?','The cube is the family''s time-travel device; this time its light behaves differently from the nine before it, flickering and moving like firelight glimpsed through a doorway rather than glowing steadily, signaling a country built around welcome rather than distance.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq06','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-06','Is this book scary or intense for younger readers?','There is real tension in an early scene where the children face a life-threatening winter storm on a mountain road, but the danger resolves quickly into rescue and warmth, and the book overall centers on comfort, hospitality, and belonging rather than danger.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq07','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-07','Does the book show ''the Maker'' or explain who built the cube?','No. Consistent with the whole series, the Maker behind the cube''s power is never depicted or shown directly; the book focuses on the mystery of the light and the wisdom the family gathers from each crossing.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq08','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-08','What historical topic does Beckah study in this installment?','Beckah completes her decade-long study of ancient writing systems by examining the highland town''s wedge-pressed law tablets, which record a strict guest-law protecting travelers — the capstone to comparisons she has drawn since Egypt in book one.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq09','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-09','What does Ellie learn from the character Halki?','Ellie learns the caravanserai''s welcome-songs, a musical tradition sung to strangers at the door to calm their fear, including the hardest one: a song for guests who don''t believe they deserve to be welcomed.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq10','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-10','What life lesson or family ''wisdom'' does this book center on?','The tenth wisdom Daniel discovers is to ''build the door wider than you think you need'' — that true strength and legacy come from keeping a home open to those who haven''t arrived yet, not from building it more closed and defended.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq11','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-11','Is this book appropriate for a classroom or homeschool history unit?','Yes. It works well alongside units on ancient Near Eastern/Anatolian civilizations, cuneiform writing, and hospitality codes such as those found in Hittite law and biblical guest-right traditions, with in-story comparisons across nine other ancient writing systems.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq12','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-12','Does this book have religious content?','Yes, as in prior installments, the Carver family''s Christian faith is woven throughout, including references to Scripture such as the Law of Moses, the cities of refuge, and Gospel parallels to the guest-law the children learn abroad.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq13','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-13','How long is the book and is it a quick read for a middle-grade reader?','The manuscript runs about 51,600 words across 30 chapters in four parts, corresponding to a 174-page paperback — consistent with the length of the earlier Cube Chronicles books.',0,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq14','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-14','Who is the stable-boy character, and why does he matter to the story?','He is an orphan who works the caravanserai''s stables and, despite living in the warm hall for years, has never felt he truly belongs there; Ellie''s realization that he needs the ''you are wanted'' welcome-song more than any stranger at the door becomes the emotional turning point of her training.',1,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq15','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-15','What is revealed about Kubaba''s ancient fire and the message carved around it?','The fire has burned unbroken for a thousand years, tended by an unbroken chain of keepers; carved words around it, which Kubaba could never read, turn out to say the stranger at the threshold is the guest the fire was built for — and Beckah reading them aloud convinces Kubaba the children are the very guests the ancient builders were waiting for.',1,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b10-faq16','10-the-fire-the-threshold-and-the-stranger-at-the-door','faq-16','How does the book end, and does it set up book eleven?','The family returns home carrying a coal from the ancient fire to keep burning in their own stove, Elizabeth reveals the meaning behind her family''s twenty-year tradition of an always-set empty chair, and the story closes with the eleventh cube light already beginning to grow in the shed, promising a new crossing ahead.',1,15,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq01','11-the-break-the-gold-and-the-palace-that-rose-again','faq-01','Is ''The Break, The Gold, and The Palace That Rose Again'' part of a series?','Yes. It is Book 11 of The Cube Chronicles by Jeremy Tinder, a middle-grade series following the Carver family as a mysterious cube transports them through different eras of history.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq02','11-the-break-the-gold-and-the-palace-that-rose-again','faq-02','Do I need to read the earlier ten books first?','It helps but isn''t required. Book 11 recaps the family''s ongoing traditions (the field notebook, the annual ''wisdom,'' the map with prior countries marked), so new readers can follow along, though longtime readers will catch more callbacks to earlier crossings.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq03','11-the-break-the-gold-and-the-palace-that-rose-again','faq-03','What historical setting does this book explore?','The Carver children travel to ancient Minoan Crete during the Bronze Age, visiting an unwalled harbor town and a great palace-complex known for its frescoes, drains, and earthquake-prone terrain.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq04','11-the-break-the-gold-and-the-palace-that-rose-again','faq-04','Who are the Carver family members in this book?','Beckah (the notebook-keeping eldest daughter), Simeon (the eldest, an aspiring builder about to leave for engineering school), Ellie (the musical thirteen-year-old), and their parents Daniel and Elizabeth.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq05','11-the-break-the-gold-and-the-palace-that-rose-again','faq-05','What is the central idea or theme of this book?','The book explores the idea that things — pottery, buildings, songs, and families — are not meant to be unbreakable, but meant to be mended, and that a repaired break, made visible rather than hidden, can be more beautiful than the original.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq06','11-the-break-the-gold-and-the-palace-that-rose-again','faq-06','Is this book appropriate for a sensitive 9-year-old?','Generally yes. It is family-friendly with no graphic content, though it includes a pastor''s honest account of a past struggle with alcoholism and touches on grief and a teenager leaving home, all handled with care and warmth.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq07','11-the-break-the-gold-and-the-palace-that-rose-again','faq-07','Does the cube itself ever get explained in this book?','No. Consistent with the series, the cube''s workings and the unseen ''Maker'' behind the family''s journeys are never fully explained or shown directly; the mystery continues to unfold gradually across the series.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq08','11-the-break-the-gold-and-the-palace-that-rose-again','faq-08','What real historical or craft traditions does the book teach?','It introduces readers to Minoan architecture and city planning, ancient clay tablet archives, and a gold-seam pottery and mural repair tradition (similar to real-world kintsugi) as a lens for talking about mending broken things.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq09','11-the-break-the-gold-and-the-palace-that-rose-again','faq-09','Is there religious content in this book?','Yes. As in prior installments, the family reads Scripture together and a local pastor delivers a sermon connecting the island''s mending culture to the Christian idea of Christ''s resurrected, scarred body; the content is presented gently within a family devotional frame.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq10','11-the-break-the-gold-and-the-palace-that-rose-again','faq-10','How does this book handle earthquakes and disaster?','Tremors and past earthquakes are discussed frequently since the island''s whole culture is built around living with and rebuilding after them, but the depictions are non-graphic and framed around resilience and craftsmanship rather than disaster horror.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq11','11-the-break-the-gold-and-the-palace-that-rose-again','faq-11','Would this book work well for a classroom or homeschool unit on ancient civilizations?','Yes. It offers an engaging introduction to Minoan Crete''s architecture, trade, and artistic traditions, along with discussion-friendly themes about repair, reconciliation, and resilience that pair well with history or character-education units.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq12','11-the-break-the-gold-and-the-palace-that-rose-again','faq-12','Is this a standalone story or does it end on a cliffhanger?','The core Minoan adventure and its lessons resolve by the end of the book, but the overarching family story continues, with hints that the family is nearing the center of a larger mystery tied to the map they''ve been building across all eleven crossings.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq13','11-the-break-the-gold-and-the-palace-that-rose-again','faq-13','What happens with Simeon by the end of the book?','Simeon completes his apprenticeship in the island''s mending and building crafts and, at the story''s close, leaves home for engineering school, becoming the first Carver child to move out — a change the family deliberately marks and honors rather than hides.',1,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq14','11-the-break-the-gold-and-the-palace-that-rose-again','faq-14','What is revealed about who has been secretly maintaining the island''s ancient mending sites?','Beckah discovers that the cave chambers and gilded repairs have been continuously tended for far longer than any civilization the family has visited, by unseen caretakers who appear to already know the family is coming and are deliberately staying out of sight to prepare a welcome.',1,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b11-faq15','11-the-break-the-gold-and-the-palace-that-rose-again','faq-15','Does the family experience a real earthquake or major crisis during the crossing?','The book focuses more on the island''s culture of repair and its rebuilt, earthquake-tested palace hall than on depicting an active catastrophic quake during the family''s stay; tension comes mostly from tremors, historical rebuilding stories, and emotional family stakes rather than an on-page disaster sequence.',1,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq01','12-the-song-the-stars-and-the-country-that-remembers','faq-01','What is book 12 of The Cube Chronicles about?','The Carver family travels to the ancient desert songline country of Australia, where the cube sings for the first time, and they learn how a people with no written language kept ten thousand years of knowledge perfectly through song.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq02','12-the-song-the-stars-and-the-country-that-remembers','faq-02','Is the exact title spelled a certain way?','Yes: The Song, The Stars, and The Country That Remembers — capitalization and punctuation should be preserved exactly as shown.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq03','12-the-song-the-stars-and-the-country-that-remembers','faq-03','Do I need to read the first eleven books to understand this one?','No. Each Cube Chronicles book stands on its own as a complete adventure, though returning readers will recognize the ongoing Carver family story, the cube''s yearly journeys, and recurring themes like Daniel''s collected ''wisdoms.''',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq04','12-the-song-the-stars-and-the-country-that-remembers','faq-04','Who are the main characters in this book?','The Carver family — parents Daniel and Elizabeth, and children Simeon, Beckah, and Ellie — along with desert guides Jarli, Alinta, Kira, and Mala, who teach them the songline traditions.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq05','12-the-song-the-stars-and-the-country-that-remembers','faq-05','Is this book appropriate for a classroom read-aloud?','Yes. It is family-friendly middle-grade fiction with no graphic content, and it introduces real historical and cultural concepts about Aboriginal Australian songlines in a respectful, age-appropriate way.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq06','12-the-song-the-stars-and-the-country-that-remembers','faq-06','What historical or cultural topic does this book explore?','It explores Aboriginal Australian songlines — oral traditions that encode navigation, law, water sources, and history in song, allowing knowledge to be preserved accurately across thousands of years without writing.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq07','12-the-song-the-stars-and-the-country-that-remembers','faq-07','Does the book depict a specific real-world religious or spiritual figure?','The book portrays Aboriginal cultural and spiritual traditions through characters like Jarli, Alinta, and Kira, alongside the Carver family''s own Christian faith; consistent with the series, the divine ''Maker'' guiding the cube is never shown or described visually.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq08','12-the-song-the-stars-and-the-country-that-remembers','faq-08','How does the cube work in this installment?','The cube glows and, for the first time in the series, produces an audible singing chord rather than only light, signaling that this journey is centered on sound and memory rather than sight.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq09','12-the-song-the-stars-and-the-country-that-remembers','faq-09','What age range is this book intended for?','Ages 9 to 13, consistent with the rest of the middle-grade Cube Chronicles series.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq10','12-the-song-the-stars-and-the-country-that-remembers','faq-10','How long is the book?','The manuscript is approximately 49,000 words, which spans 176 pages in the KDP paperback edition across 30 chapters in four parts.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq11','12-the-song-the-stars-and-the-country-that-remembers','faq-11','What lesson does Daniel learn in this book?','Daniel comes to see that his twelfth ''wisdom'' — ''build it into the song'' — means that lasting legacy isn''t built from durable materials but from knowledge and values passed faithfully from person to person.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq12','12-the-song-the-stars-and-the-country-that-remembers','faq-12','Does Simeon have his own adventure in this book?','Yes, Simeon undertakes a solo two-day walk across the desert guided only by a memorized song, which becomes a turning point in his understanding of faith and trust.',1,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq13','12-the-song-the-stars-and-the-country-that-remembers','faq-13','What does Ellie discover about her own singing and memory?','Ellie learns that the desert songkeepers preserve knowledge with total precision through melody, rhyme, and repetition, and she becomes inspired to found her own ''songline'' tradition for her neighborhood back home.',1,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq14','12-the-song-the-stars-and-the-country-that-remembers','faq-14','Does the family find a connection between the ancient songline and their own family traditions?','Yes — Beckah realizes that the family''s twelve years of yearly recorded ''wisdoms'' and rituals form their own songline, built in parallel with the ancient one, suggesting the two are meant to eventually meet.',1,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq15','12-the-song-the-stars-and-the-country-that-remembers','faq-15','Is there a cliffhanger or hook into the next book?','The book ends with a new, thirteenth glow beginning to grow in the cube and strong hints that the family''s own songline and the ancient songline are converging, setting up the next adventure.',0,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq16','12-the-song-the-stars-and-the-country-that-remembers','faq-16','Would this book work well for a parent-child read-aloud unit on world cultures?','Yes, it pairs an engaging adventure story with genuine educational content about oral history, memory, and Aboriginal Australian culture, making it suitable for family read-alouds or supplemental cultural studies.',0,15,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b12-faq17','12-the-song-the-stars-and-the-country-that-remembers','faq-17','Are there any content concerns parents or librarians should know about?','None beyond typical middle-grade adventure content; the book contains no violence, romance, or mature themes, and treats its cultural and religious material with care.',0,16,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq01','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-01','What is book 13 in the Cube Chronicles series called?','Book 13 is titled The Canoe, The Compass, and The Shore Beyond the Sky, subtitled A Time-Travel Adventure on the Ancient Pacific.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq02','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-02','Where and when does this book take place?','The Carver family travels to an ancient Pacific voyaging culture, sailing the open ocean between island waypoints in a world of star-compass navigation, outrigger canoes, and oral wayfinding chants -- the thirteenth stop on their historical journey.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq03','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-03','Do I need to read the previous 12 books first?','No prior reading is required to follow the plot, but the series builds a cumulative family history -- references to the Carvers'' eleven prior ''warnings,'' twelve prior lights, and past countries (including Egypt) will mean more to readers who have followed the earlier books.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq04','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-04','How does the cube (or ''light'') transport the family this time?','The mysterious light behaves differently than in past adventures: instead of simply glowing, it leans and streams steadily toward one direction, like a compass needle, giving the family their first sense that this journey is about following a bearing rather than arriving at a fixed place.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq05','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-05','Who are the main characters in this installment?','The core Carver family returns -- parents Daniel and Elizabeth, and children Simeon, Beckah, and Ellie -- alongside new characters from the voyaging culture: master navigator Puanga, young apprentice navigator Manu, and Beckah''s watch-mate Tuila.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq06','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-06','Is this book appropriate for middle-grade readers?','Yes. It is family-friendly with no violence, romance, or objectionable content. It includes emotionally serious moments -- a long, difficult sea passage and a parent''s retelling of a hard past journey -- handled with warmth and age-appropriate care.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq07','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-07','What real-world history or culture does this book teach?','The book introduces the navigation traditions of ancient Pacific voyaging societies: reading stars, swells, clouds, and birds without instruments, building and lashing ocean-going canoes, and passing down navigational knowledge through memorized chant rather than written charts.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq08','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-08','Is the cube''s guiding force (''the Maker'') ever shown directly?','No. Consistent with the whole series, the divine presence referred to by the family is felt through signs, provision, and guidance, but is never depicted or shown visibly on the page.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq09','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-09','What is Beckah''s personal struggle in this book?','Beckah, now 17 and facing college applications, is stuck on the ''intended course of study'' line because she feels she has no clear calling -- a real-world worry about the future that mirrors the wayfinders'' practice of steering toward a shore you cannot yet see.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq10','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-10','Does this book work as a standalone gift or classroom read?','Yes. While it rewards series fans, the central voyage story, navigation lessons, and family dynamics are self-contained and suitable for independent reading, family read-alouds, or classroom units on Pacific history and exploration.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq11','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-11','How long is this book?','The Canoe, The Compass, and The Shore Beyond the Sky is about 49,000 words, running 174 pages in the KDP paperback edition -- consistent with the series'' typical middle-grade chapter-book length.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq12','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-12','Are there illustrations or a glossary of navigation terms?','The manuscript text itself is prose-only; navigational concepts like the star compass, swell-reading, and voyaging chants are explained through dialogue and the characters'' own note-taking rather than diagrams.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq13','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-13','What does Elizabeth Carver''s backstory reveal in this book?','Book 13 reveals, in full for the first time, the story of Elizabeth''s own youthful ocean crossing as an immigrant -- a two-year period of hardship and courage that the family comes to see as the ''founding voyage'' behind their whole family''s spirit of travel.',1,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq14','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-14','Does the family successfully complete the ocean voyage and reach their destination?','Yes -- after a real, three-day open-water passage that Beckah navigates herself using only memorized chants, the family reaches a remote island holding a carved chamber that ties together lessons from all twelve prior countries they''ve visited.',1,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b13-faq15','13-the-canoe-the-compass-and-the-shore-beyond-the-sky','faq-15','What happens at the very end of the book?','Back home for Christmas, the family reflects that their journey is now in its final approach, gains a new young apprentice recorder named Marisol, and notices a fourteenth light beginning to grow, setting up the next book in the series.',1,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq01','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-01','What is ''The Crossroads, The Weave, and The Road of All Roads'' about?','It''s Book 14 of The Cube Chronicles, in which the Carver family''s magic cube shows them a light woven of every color at once and carries them to a great Silk Road crossroads city, where they learn from master weavers, dyers, and caravan-masters while working, back home, to heal a long family rift.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq02','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-02','Where and when is this book set?','The children travel to a bustling caravanserai city at a major junction of the ancient Silk Road, a crossroads where caravans, goods, and peoples from many nations gather and trade.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq03','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-03','Do I need to read the previous 13 books first?','The book stands alone as an adventure, but it pays off long-running family threads (the record shelf, Beckah''s writing, Ellie''s singing, Simeon''s craftsmanship, and a family mystery about Uncle Ray) that build across the series, so reading in order gives the fullest experience.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq04','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-04','Who are the Carver children and what do they each learn in this book?','Beckah studies with the master weaver Zarina and learns to ''read'' a carpet''s woven history; Ellie apprentices with the dyer Sanam and learns the power of a unifying ''weaving voice'' in song; Simeon apprentices with the caravan-master Rashid and learns to hold together a train of different, sometimes clashing, travelers and goods.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq05','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-05','Is the cube ever explained or shown to be operated by a visible being?','No. The cube''s light and guidance are treated as a mysterious, unseen force tied to family faith; the Maker/Weaver is referenced in prayer and metaphor but is never depicted as a visible character.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq06','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-06','Is this book appropriate for younger middle-grade readers?','Yes, it is family-friendly with no graphic violence. The most mature material is emotional: a family works through decades of estrangement and hard feelings, handled with care and resolved through honesty and forgiveness.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq07','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-07','What historical topics does this book teach?','Readers learn about Silk Road trade routes, life in a caravanserai, the role of a caravan-master leading mixed trade trains, traditional hand-weaving and carpet-making, and natural dyeing techniques.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq08','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-08','Who is Uncle Ray, and why does he matter in this book?','Uncle Ray is Daniel Carver''s estranged brother. A rift between them, dating back decades to a family dispute, has quietly shadowed the Carver household. This book''s home storyline follows the family''s decision to invite him back and repair the relationship.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq09','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-09','Does the book deal with real family conflict, and how is it resolved?','Yes. The Carvers confront a twenty-six-year silence between Daniel and his brother, stemming from disputes over their father''s business and final illness. It is resolved through honest confession from both brothers and a family reunion, modeling healthy conflict resolution for young readers.',1,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq10','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-10','What does the ''weaving voice'' Ellie learns represent?','Sanam teaches Ellie that a unifying melody sung at moments of fear or division can help a frightened crowd feel like one people rather than turn against strangers — a lesson rooted in a story about a caravan nearly turned away from a city gate.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq11','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-11','Is there any romance or mature content in this book?','No romantic content. The book is centered on family relationships, craftsmanship, faith, and historical adventure, suitable for middle-grade readers.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq12','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-12','What happens with Beckah''s college storyline?','Beckah receives college acceptance letters throughout the book and, by the end, chooses a school for its strength in writing and historical record-keeping — paralleling the book''s themes of belonging and choosing where one''s own ''thread'' ties in.',1,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq13','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-13','Does this book set up a fifteenth book in the series?','Yes. The family''s woven record shows all fourteen threads tied except one final, central one, and a ''fifteenth tooth'' is described as already growing, hinting at one more country and a final revelation to come.',0,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq14','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-14','Is this a good book for a classroom studying the Silk Road?','Yes. It''s well suited to a unit on Silk Road trade and cultures, offering an accessible, story-driven introduction to caravanserais, trade goods, weaving and dyeing crafts, and the diversity of peoples along the trade routes.',0,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq15','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-15','How does the family''s faith show up in this book?','The Carvers pray together, read Scripture (including Ephesians 1 on the gathering of all things), and interpret their adventure and their family reconciliation as part of a larger faith journey, without ever depicting God as a visible character.',0,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b14-faq16','14-the-crossroads-the-weave-and-the-road-of-all-roads','faq-16','What is the significance of the title''s three parts?','The Crossroads is the city where all roads meet; the Weave is the carpet-making and record-keeping craft the family learns; and the Road of All Roads reflects the deeper theme that a place gathering every path together is more valuable than any single, singular route.',0,15,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq01','15-the-center-the-maker-and-the-road-that-was-always-home','faq-01','What is Book 15 of the Cube Chronicles about?','It''s the finale of the series. The Carver family''s traveling cube produces a white light unlike any of its previous fourteen signals, leading them on one last, culminating journey that ties together everything they''ve learned across the series, during the final summer before eldest daughter Beckah leaves for college.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq02','15-the-center-the-maker-and-the-road-that-was-always-home','faq-02','Do I need to read the first 14 books before this one?','Yes. This book is written as the capstone of the series and constantly calls back to characters, crafts, and lessons from all fourteen previous installments. New readers should start from Book 1.',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq03','15-the-center-the-maker-and-the-road-that-was-always-home','faq-03','Who are the main characters in this book?','The Carver family: father Daniel (a builder), mother Elizabeth (who emigrated from the Philippines as a young woman), and their three children — Simeon, Beckah, and Ellie — each of whom has developed a distinct craft (building, record-keeping, and singing) over the course of the series.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq04','15-the-center-the-maker-and-the-road-that-was-always-home','faq-04','Does the cube still transport the family through history in this book?','The cube is central to the story, but this final light behaves differently from earlier ones — rather than pointing outward to a new historical era, it points inward, toward a culminating destination tied to the family''s entire fifteen-year journey.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq05','15-the-center-the-maker-and-the-road-that-was-always-home','faq-05','Is this book appropriate for my child?','Yes. It is written for the same middle-grade audience as the rest of the series (roughly ages 8-12) and contains no violence, romance, or frightening content. It does include reflective, faith-themed material and emotional moments around grief, growing up, and family change.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq06','15-the-center-the-maker-and-the-road-that-was-always-home','faq-06','Is there religious content in this book?','Yes, more than in earlier volumes. The finale explores themes of faith, gratitude, and a guiding figure referred to as ''the Maker,'' treated with reverence and restraint rather than shown as a visible character. Parents who prefer to know in advance should be aware the tone turns spiritual and reflective in this final book.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq07','15-the-center-the-maker-and-the-road-that-was-always-home','faq-07','Who is ''the Maker'' mentioned in the title?','The Maker is spoken of throughout the series as the unseen guiding presence behind the family''s journeys. Consistent with how the series has always handled this idea, the Maker is never physically described or portrayed as an on-page character — the story keeps this figure a matter of reverence rather than depiction.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq08','15-the-center-the-maker-and-the-road-that-was-always-home','faq-08','What grade level or age range is this book best suited for?','It''s aimed at middle-grade readers, roughly ages 8-12, matching the reading level and thematic maturity of the rest of the Cube Chronicles.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq09','15-the-center-the-maker-and-the-road-that-was-always-home','faq-09','How long is this book?','The manuscript is approximately 48,700 words, which comes to about 164 pages in the KDP paperback edition — in line with other books in the series.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq10','15-the-center-the-maker-and-the-road-that-was-always-home','faq-10','Is this a good book for a classroom read-aloud or literature circle?','It works well as a capstone discussion text for a class that has already read the earlier books, since it revisits many prior settings and lessons. Teachers should preview the reflective, faith-themed final chapters before assigning them, given the material''s tone.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq11','15-the-center-the-maker-and-the-road-that-was-always-home','faq-11','Does this book focus on one specific historical era like earlier books did?','No — rather than visiting a single new historical setting, this finale gathers together characters, crafts, and memories from many of the eras visited earlier in the series as the family reaches its culminating destination.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq12','15-the-center-the-maker-and-the-road-that-was-always-home','faq-12','What does Elizabeth''s backstory add to this book?','Elizabeth, the Carver children''s mother, emigrated from Pampanga in the Philippines as a young woman. This book gives special attention to her lifelong experience of feeling caught between two homes, offering a moving perspective on immigrant identity and belonging.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq13','15-the-center-the-maker-and-the-road-that-was-always-home','faq-13','Is Beckah leaving for college a major plot point?','Yes. The story takes place during the last summer before Beckah, the eldest Carver child, departs for college, and her transition into her own path is woven throughout the family''s final journey.',0,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq14','15-the-center-the-maker-and-the-road-that-was-always-home','faq-14','Are there librarian-relevant content advisories for this book?','The book is family-friendly with no profanity, violence, or romantic content, but librarians cataloging for faith-sensitive collections should note its pronounced spiritual and gratitude-themed content in the second half, more prominent here than in earlier series entries.',0,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq15','15-the-center-the-maker-and-the-road-that-was-always-home','faq-15','Do familiar characters from earlier books reappear?','Yes — several mentors and friends the Carver children met on past crossings, including the weaver Zarina and the mending artisan Rhaya, return in this finale as the family''s journeys come full circle.',0,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq16','15-the-center-the-maker-and-the-road-that-was-always-home','faq-16','How does the Cube Chronicles series end?','SPOILER: The family completes its final crossing and learns the deeper purpose behind all fifteen years of their travels — discovering they were not only builders and carriers of what they learned, but were themselves being shaped along the way. They return home transformed, understanding their ordinary house as a place meant to welcome and provision others, and the series closes with the family settled at home, its long journey complete.',1,15,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq17','15-the-center-the-maker-and-the-road-that-was-always-home','faq-17','Does anyone in the family choose not to come home in the end?','SPOILER: No — the whole immediate Carver family reaches the end of the road together, though the story acknowledges, in an emotional passage, that not every traveler on every road chooses to complete the journey, which becomes part of why the family sees its ongoing work as meaningful.',1,16,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('b15-faq18','15-the-center-the-maker-and-the-road-that-was-always-home','faq-18','Does the traveling cube still work after this book, or is its story finished?','SPOILER: By the end of the book, the cube''s long task is described as complete, and it comes to rest — this is written as the conclusion of its role in the family''s life and the series as a whole.',1,17,'2026-07-14T00:00:00.000Z');

INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq01',NULL,'faq-01','What is The Cube Chronicles?','The Cube Chronicles is a fifteen-book middle-grade historical time-travel adventure series by Jeremy Tinder. It follows the Carver family — three siblings and their parents — after the children discover a mysterious nine-sided cube beneath their backyard shed that carries them across the ancient world, one civilization per book.',0,0,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq02',NULL,'faq-02','How many books are in the series?','There are fifteen books. The series is complete, running in reading order from Book 1 (ancient Egypt) to Book 15 (the culmination of the journey).',0,1,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq03',NULL,'faq-03','Do the books need to be read in order?','We recommend reading in order. Each book is a self-contained adventure to a new time and place, but the family''s story, relationships, and running threads — Daniel''s yearly "wisdoms," Beckah''s record-keeping, the cube''s growing pattern — build from book to book, and the emotional payoff is richest in sequence. Book 1 introduces the family, the shed, and the cube, so it is the best place to start.',0,2,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq04',NULL,'faq-04','What age group is the series for?','The series is written for middle-grade readers, roughly ages 8 to 12, and is frequently enjoyed as a family read-aloud by younger and older readers alike. The vocabulary is rich and the history is real, which also makes the books useful for classrooms and homeschool.',0,3,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq05',NULL,'faq-05','Is the series appropriate for a family read-aloud?','Yes. The books are family-centered and family-friendly, with no profanity, no romance, and only mild adventure-level peril. They are written to be read aloud across ages, and each book explores discussion-worthy themes about family, work, and character.',0,4,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq06',NULL,'faq-06','Who is the author?','The series is written by Jeremy Tinder, author of The Cube Chronicles. He writes the Carver family across the ancient world and has said that the foundation of every good story, like the foundation of every good building, is love.',0,5,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq07',NULL,'faq-07','Who are the main characters?','The three Carver siblings — Simeon (a builder), Beckah (the family''s record-keeper) and Ellie (the family''s singer) — along with their parents, Daniel, a builder and carpenter, and Elizabeth, their Filipina-American mother. Each book also introduces friends and mentors from the civilization the children visit.',0,6,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq08',NULL,'faq-08','Where and when is the series set?','Each book has a contemporary family frame (beginning in 1986 in the rural Carolinas) and a central adventure in a real ancient civilization. Across the series the children visit Egypt, Greece, the Indus Valley, China, Japan, Sumer, the Andes, the Amazon, the Pacific Northwest coast, Anatolia, Minoan Crete, Aboriginal Australia, the Pacific voyaging world, and the Silk Road.',0,7,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq09',NULL,'faq-09','Is the history based on real civilizations?','Yes. Every destination is grounded in a real historical culture, and the books weave in accurate detail about how people built, farmed, wrote, healed, traded, navigated, and made music. The one fantastical element is the cube itself.',0,8,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq10',NULL,'faq-10','Does the series contain time travel or fantasy?','Yes — a mysterious nine-sided cube transports the children through history. Apart from the cube, the stories stay grounded in realistic historical and family life; there is no magic system, monsters, or spellcasting.',0,9,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq11',NULL,'faq-11','Is the series suitable for classrooms or homeschool?','Very much so. Each book pairs an adventure story with a real ancient civilization and its crafts and ideas, and several books include discussion questions, historical notes, and vocabulary. Teachers and homeschool families use the series alongside world-history and geography units.',0,10,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq12',NULL,'faq-12','What themes does the series explore?','Recurring themes include family, history, faith, craftsmanship and honest work, courage, responsibility, hospitality and generosity, and homecoming. Each book adds one of the father''s "wisdoms" about building — and about building a life.',0,11,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq13',NULL,'faq-13','Is the series frightening or violent?','No. There are moments of adventure-level tension — a storm, a river animal, a hard journey — but no graphic violence or gore. A few later books touch gently on grief and loss, always handled with warmth and care.',0,12,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq14',NULL,'faq-14','Does the series contain religious or faith themes?','Yes. The Carver family is a Christian family, and their faith — prayer, Scripture, gratitude, hospitality — is woven naturally into their everyday life and travels. It is presented warmly rather than as instruction, and it deepens the family''s reflections on what they learn.',0,13,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq15',NULL,'faq-15','Is God or "the Maker" shown as a character?','No. A guiding, unseen presence the family calls "the Maker" is spoken of with reverence throughout the series, but is never depicted, described, or shown as a visible character. The final book keeps that same restraint.',0,14,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq16',NULL,'faq-16','How long are the books?','Lengths vary. The first book is the longest at about 591 print pages, and later books settle into a briefer 165–220 page range. Across all fifteen, the series runs about 3,861 paperback pages.',0,15,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq17',NULL,'faq-17','What will readers learn about history and culture?','Readers encounter how the Great Pyramid was really built, how the Parthenon was raised, how the Indus Valley planned its cities, how bronze was cast in ancient China, how Jōmon potters and Pacific wayfinders worked, how the Andes engineered rope bridges, how the Amazon built living soil, and much more — always through the eyes of children learning a craft.',0,16,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq18',NULL,'faq-18','Which book should I start with?','Start with Book 1, The Shed, The Cube, and The Sands of Time. It introduces the Carver family, the discovery of the cube, and the first crossing to ancient Egypt, and sets up everything that follows.',0,17,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq19',NULL,'faq-19','Is the series finished, or are more books coming?','The series is complete at fifteen books, telling a full arc from the first crossing to the journey''s center. Each book''s ending hints at the next, and Book 15 brings the whole spiral home.',0,18,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq20',NULL,'faq-20','Are the books standalone or one continuous story?','Both. Each book is a complete adventure to one destination that can be enjoyed on its own, but together they form a single continuous story about a family growing up and growing closer across fifteen years of travel.',0,19,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq21',NULL,'faq-21','Where can I buy the books?','Purchase links for each book appear on that book''s page. Retailer links are configured per book; where a link is still being finalized it is clearly marked as a placeholder until the official store link is available.',0,20,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq22',NULL,'faq-22','Can my child ask questions about the books on this site?','Yes. Registered and verified readers can submit questions on any book''s page. Questions and answers are reviewed by a moderator before they appear publicly, so the community stays safe and on-topic. You never need an account just to read the books'' editorial FAQs.',0,21,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq23',NULL,'faq-23','How does the community Q&A work?','Readers can register with a display name and email, verify their email, and then ask questions or post answers and comments on a book''s discussion. Everything is moderated before publishing. If you ask a question, you''re automatically subscribed to be notified by email when an approved answer is posted, and you can unsubscribe at any time.',0,22,'2026-07-14T00:00:00.000Z');
INSERT OR REPLACE INTO editorial_faqs (id,book_slug,anchor,question,answer,is_spoiler,sort_order,updated_at) VALUES ('series-faq24',NULL,'faq-24','How is my email address used?','Your email is used only to verify your account and to send the discussion notifications you''ve asked for. Email addresses are never displayed publicly or sold, and every notification includes an unsubscribe link. See the Privacy Policy for full details.',0,23,'2026-07-14T00:00:00.000Z');
